137:     // WRITE RESPONSE CHANNEL
138:     input  logic                        axi_master_b_valid,
139:     input  logic [1:0]                  axi_master_b_resp,
140:     input  logic [AXI_ID_WIDTH-1:0]     axi_master_b_id,
141:     input  logic [AXI_USER_WIDTH-1:0]   axi_master_b_user,
142:     output logic                        axi_master_b_ready
143:   );
144: 
145:   // Registers
146:   logic [AXI_DATA_WIDTH/8-1:0]    sel_reg;
147:   logic   [AXI_ADDR_WIDTH-1:0]    addr_reg;  // Don't really need the two LSB, this info is in the SEL bits
148:   logic   [AXI_DATA_WIDTH-1:0]    data_in_reg;  // dbg->AXI
149:   logic   [AXI_DATA_WIDTH-1:0]    data_out_reg;  // AXI->dbg
150:   logic                           wr_reg;
151:   logic                           str_sync;  // This is 'active-toggle' rather than -high or -low.
152:   logic                           rdy_sync;  // ditto, active-toggle
153:   logic                           err_reg;
154: 
155:   // Sync registers.  TFF indicates TCK domain, WBFF indicates wb_clk domain
156:   logic     rdy_sync_tff1;
157:   logic     rdy_sync_tff2;
158:   logic     rdy_sync_tff2q;  // used to detect toggles
159:   logic     str_sync_wbff1;
160:   logic     str_sync_wbff2;
161:   logic     str_sync_wbff2q;  // used to detect toggles
162: 
163: 
164:   // Control Signals
165:   logic     data_o_en;    // latch wb_data_i
166:   logic     rdy_sync_en;  // toggle the rdy_sync signal, indicate ready to TCK domain
167:   logic     err_en;       // latch the wb_err_i signal
168: 
169:   // Internal signals
170:   logic [AXI_DATA_WIDTH/8-1:0] be_dec;        // word_size and low-order address bits decoded to SEL bits
171:   logic                        start_toggle;  // AXI domain, indicates a toggle on the start strobe
172:   logic   [AXI_DATA_WIDTH-1:0] swapped_data_i;
173:   logic   [AXI_DATA_WIDTH-1:0] swapped_data_out;
174: 
175:   // AXI4 FSM states
