179: 
180:   // Create byte enable signals from word_size and address (combinatorial)
181:   // This uses LITTLE ENDIAN byte ordering...lowest-addressed bytes is the
182:   // least-significant byte of the 32-bit WB bus.
183:   always_comb
184:   begin
185:     if (AXI_DATA_WIDTH == 64)
186:     begin
187:       case (word_size_i)
188:         4'h1:
189:           begin
190:             if(addr_i[2:0] == 3'b000)      be_dec = 8'b00000001;
191:             else if(addr_i[2:0] == 3'b001) be_dec = 8'b00000010;
192:             else if(addr_i[2:0] == 3'b010) be_dec = 8'b00000100;
193:             else if(addr_i[2:0] == 3'b011) be_dec = 8'b00001000;
194:             else if(addr_i[2:0] == 3'b100) be_dec = 8'b00010000;
195:             else if(addr_i[2:0] == 3'b101) be_dec = 8'b00100000;
196:             else if(addr_i[2:0] == 3'b110) be_dec = 8'b01000000;
197:             else                           be_dec = 8'b10000000;
198:           end
199:         4'h2:
200:           begin
201:             if(addr_i[2:1] == 2'b00)       be_dec = 8'b00000011;
202:             else if(addr_i[2:1] == 2'b01)  be_dec = 8'b00001100;
203:             else if(addr_i[2:1] == 2'b10)  be_dec = 8'b00110000;
204:             else                           be_dec = 8'b11000000;
205:           end
206:         4'h4:
207:           begin
208:             if(addr_i[2] == 1'b0)          be_dec = 8'b00001111;
209:             else                           be_dec = 8'b11110000;
210:           end
211:         4'h8:                              be_dec = 8'b11111111;
212:         default:                           be_dec = 8'b11111111;  // default to 64-bit access
213:       endcase
214:     end
215:     else if (AXI_DATA_WIDTH == 32)
216:     begin
217:       case (word_size_i)
218:         4'h1:
219:           begin
220:             if(addr_i[1:0] == 2'b00)       be_dec = 4'b0001;
221:             else if(addr_i[1:0] == 2'b01)  be_dec = 4'b0010;
222:             else if(addr_i[1:0] == 2'b10)  be_dec = 4'b0100;
223:             else                           be_dec = 4'b1000;
224:           end
225:         4'h2:
226:           begin
227:             if(addr_i[1] == 1'b0)          be_dec = 4'b0011;
228:             else                           be_dec = 4'b1100;
229:           end
230:         4'h4:
231:                                            be_dec = 4'b1111;
232:         4'h8:
233:                                            be_dec = 4'b1111;  //error if it happens
234:         default:                           be_dec = 4'b1111;  // default to 32-bit access
235:       endcase // word_size_i
236:     end
237:   end
