240:   // Byte- or word-swap data as necessary.  Use the non-latched be_dec signal,
241:   // since it and the swapped data will be latched at the same time.
242:   // Remember that since the data is shifted in LSB-first, shorter words
243:   // will be in the high-order bits. (combinatorial)
244:   always_comb
245:   begin
246:     if (AXI_DATA_WIDTH == 64)
247:     begin
248:       case (be_dec)
249:         8'b00001111: swapped_data_i = {32'h0, data_i[63:32]};
250:         8'b11110000: swapped_data_i = {       data_i[63:32],  32'h0};
251:         8'b00000011: swapped_data_i = {48'h0, data_i[63:48]};
252:         8'b00001100: swapped_data_i = {32'h0, data_i[63:48], 16'h0};
253:         8'b00110000: swapped_data_i = {16'h0, data_i[63:48], 32'h0};
254:         8'b11000000: swapped_data_i = {       data_i[63:48], 48'h0};
255:         8'b00000001: swapped_data_i = {56'h0, data_i[63:56]};
256:         8'b00000010: swapped_data_i = {48'h0, data_i[63:56],  8'h0};
257:         8'b00000100: swapped_data_i = {40'h0, data_i[63:56], 16'h0};
258:         8'b00001000: swapped_data_i = {32'h0, data_i[63:56], 24'h0};
259:         8'b00010000: swapped_data_i = {24'h0, data_i[63:56], 32'h0};
260:         8'b00100000: swapped_data_i = {16'h0, data_i[63:56], 40'h0};
261:         8'b01000000: swapped_data_i = { 8'h0, data_i[63:56], 48'h0};
262:         8'b10000000: swapped_data_i = {       data_i[63:56], 56'h0};
263:         default:     swapped_data_i =         data_i;
264:       endcase
265:     end
266:     else if (AXI_DATA_WIDTH == 32)
267:     begin
268:       case (be_dec)
269:         4'b1111: swapped_data_i =         data_i[63:32];
270:         4'b0011: swapped_data_i = {16'h0, data_i[63:48]};
271:         4'b1100: swapped_data_i = {       data_i[63:48], 16'h0};

